399	// nodeValue holds return values of (*Node).getValue method
400	type nodeValue struct {
401		handlers HandlersChain
402		params   *Params
403		tsr      bool
404		fullPath string
405	}
406	
407	type skippedNode struct {
408		path        string
409		node        *node
410		paramsCount int16
411	}
412	
413	// Returns the handle registered with the given path (key). The values of
414	// wildcards are saved to a map.
415	// If no handle can be found, a TSR (trailing slash redirect) recommendation is
416	// made if a handle exists with an extra (without the) trailing slash for the
417	// given path.
418	func (n *node) getValue(path string, params *Params, skippedNodes *[]skippedNode, unescape bool) (value nodeValue) {
419		var globalParamsCount int16
420	
421	walk: // Outer loop for walking the tree
422		for {
423			prefix := n.path
424			if len(path) > len(prefix) {
425				if path[:len(prefix)] == prefix {
426					path = path[len(prefix):]
427	
428					// Try all the non-wildcard children first by matching the indices
429					idxc := path[0]
430					for i, c := range []byte(n.indices) {
431						if c == idxc {
432							//  strings.HasPrefix(n.children[len(n.children)-1].path, ":") == n.wildChild
433							if n.wildChild {
434								index := len(*skippedNodes)
435								*skippedNodes = (*skippedNodes)[:index+1]
436								(*skippedNodes)[index] = skippedNode{
437									path: prefix + path,
438									node: &node{
439										path:      n.path,
440										wildChild: n.wildChild,
441										nType:     n.nType,
442										priority:  n.priority,
443										children:  n.children,
444										handlers:  n.handlers,
445										fullPath:  n.fullPath,
446									},
447									paramsCount: globalParamsCount,
448								}
449							}
450	
451							n = n.children[i]
452							continue walk
453						}
454					}
455	
456					if !n.wildChild {
457						// If the path at the end of the loop is not equal to '/' and the current node has no child nodes
458						// the current node needs to roll back to last valid skippedNode
459						if path != "/" {
460							for length := len(*skippedNodes); length > 0; length-- {
461								skippedNode := (*skippedNodes)[length-1]
462								*skippedNodes = (*skippedNodes)[:length-1]
463								if strings.HasSuffix(skippedNode.path, path) {
464									path = skippedNode.path
465									n = skippedNode.node
466									if value.params != nil {
467										*value.params = (*value.params)[:skippedNode.paramsCount]
468									}
469									globalParamsCount = skippedNode.paramsCount
470									continue walk
471								}
472							}
473						}
474	
475						// Nothing found.
476						// We can recommend to redirect to the same URL without a
477						// trailing slash if a leaf exists for that path.
478						value.tsr = path == "/" && n.handlers != nil
479						return value
480					}
481	
482					// Handle wildcard child, which is always at the end of the array
483					n = n.children[len(n.children)-1]
484					globalParamsCount++
485	
486					switch n.nType {
487					case param:
488						// fix truncate the parameter
489						// tree_test.go  line: 204
490	
491						// Find param end (either '/' or path end)
492						end := 0
493						for end < len(path) && path[end] != '/' {
494							end++
495						}
496	
497						// Save param value
498						if params != nil {
499							// Preallocate capacity if necessary
500							if cap(*params) < int(globalParamsCount) {
501								newParams := make(Params, len(*params), globalParamsCount)
502								copy(newParams, *params)
503								*params = newParams
504							}
505	
506							if value.params == nil {
507								value.params = params
508							}
509							// Expand slice within preallocated capacity
510							i := len(*value.params)
511							*value.params = (*value.params)[:i+1]
512							val := path[:end]
513							if unescape {
514								if v, err := url.QueryUnescape(val); err == nil {
515									val = v
516								}
517							}
518							(*value.params)[i] = Param{
519								Key:   n.path[1:],
520								Value: val,
521							}
522						}
523	
524						// we need to go deeper!
525						if end < len(path) {
526							if len(n.children) > 0 {
527								path = path[end:]
528								n = n.children[0]
529								continue walk
530							}
531	
532							// ... but we can't
533							value.tsr = len(path) == end+1
534							return value
535						}
536	
537						if value.handlers = n.handlers; value.handlers != nil {
538							value.fullPath = n.fullPath
539							return value
540						}
541						if len(n.children) == 1 {
542							// No handle found. Check if a handle for this path + a
543							// trailing slash exists for TSR recommendation
544							n = n.children[0]
545							value.tsr = (n.path == "/" && n.handlers != nil) || (n.path == "" && n.indices == "/")
546						}
547						return value
548	
549					case catchAll:
550						// Save param value
551						if params != nil {
552							// Preallocate capacity if necessary
553							if cap(*params) < int(globalParamsCount) {
554								newParams := make(Params, len(*params), globalParamsCount)
555								copy(newParams, *params)
556								*params = newParams
557							}
558	
559							if value.params == nil {
560								value.params = params
561							}
562							// Expand slice within preallocated capacity
563							i := len(*value.params)
564							*value.params = (*value.params)[:i+1]
565							val := path
566							if unescape {
567								if v, err := url.QueryUnescape(path); err == nil {
568									val = v
569								}
570							}
571							(*value.params)[i] = Param{
572								Key:   n.path[2:],
573								Value: val,
574							}
575						}
576	
577						value.handlers = n.handlers
578						value.fullPath = n.fullPath
579						return value
580	
581					default:
582						panic("invalid node type")
583					}
584				}
585			}
586	
587			if path == prefix {
588				// If the current path does not equal '/' and the node does not have a registered handle and the most recently matched node has a child node
589				// the current node needs to roll back to last valid skippedNode
590				if n.handlers == nil && path != "/" {
591					for length := len(*skippedNodes); length > 0; length-- {
592						skippedNode := (*skippedNodes)[length-1]
593						*skippedNodes = (*skippedNodes)[:length-1]
594						if strings.HasSuffix(skippedNode.path, path) {
595							path = skippedNode.path
596							n = skippedNode.node
597							if value.params != nil {
598								*value.params = (*value.params)[:skippedNode.paramsCount]
599							}
600							globalParamsCount = skippedNode.paramsCount
601							continue walk
602						}
603					}
604					//	n = latestNode.children[len(latestNode.children)-1]
605				}
606				// We should have reached the node containing the handle.
607				// Check if this node has a handle registered.
608				if value.handlers = n.handlers; value.handlers != nil {
609					value.fullPath = n.fullPath
610					return value
611				}
612	
613				// If there is no handle for this route, but this route has a
614				// wildcard child, there must be a handle for this path with an
615				// additional trailing slash
616				if path == "/" && n.wildChild && n.nType != root {
617					value.tsr = true
618					return value
619				}
620	
621				if path == "/" && n.nType == static {
622					value.tsr = true
623					return value
624				}
625	
626				// No handle found. Check if a handle for this path + a
627				// trailing slash exists for trailing slash recommendation
628				for i, c := range []byte(n.indices) {
629					if c == '/' {
630						n = n.children[i]
631						value.tsr = (len(n.path) == 1 && n.handlers != nil) ||
632							(n.nType == catchAll && n.children[0].handlers != nil)
633						return value
634					}
635				}
636	
637				return value
638			}
639	
640			// Nothing found. We can recommend to redirect to the same URL with an
641			// extra trailing slash if a leaf exists for that path
642			value.tsr = path == "/" ||
643				(len(prefix) == len(path)+1 && prefix[len(path)] == '/' &&
644					path == prefix[:len(prefix)-1] && n.handlers != nil)
645	
646			// roll back to last valid skippedNode
647			if !value.tsr && path != "/" {
648				for length := len(*skippedNodes); length > 0; length-- {
649					skippedNode := (*skippedNodes)[length-1]
650					*skippedNodes = (*skippedNodes)[:length-1]
651					if strings.HasSuffix(skippedNode.path, path) {
652						path = skippedNode.path
653						n = skippedNode.node
654						if value.params != nil {
655							*value.params = (*value.params)[:skippedNode.paramsCount]
656						}
657						globalParamsCount = skippedNode.paramsCount
658						continue walk
659					}
660				}
661			}
662	
663			return value
664		}
665	}
